import React, { useState, useEffect } from 'react';
import './AdminDashboard.css';

const AdminDashboard = ({ admin, onLogout }) => {
  const [activeTab, setActiveTab] = useState('overview');
  const [stats, setStats] = useState({});
  const [recentActivities, setRecentActivities] = useState([]);
  const [pendingAppointments, setPendingAppointments] = useState([]);
  const [pendingDoctors, setPendingDoctors] = useState([]);
  const [pendingPatients, setPendingPatients] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const headers = {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      };

      // Fetch statistics
      const statsResponse = await fetch('http://localhost:5002/api/admin/stats', { headers });
      const statsData = await statsResponse.json();
      setStats(statsData);

      // Fetch recent activities
      const activitiesResponse = await fetch('http://localhost:5002/api/admin/recent-activities', { headers });
      const activitiesData = await activitiesResponse.json();
      setRecentActivities(activitiesData);

      // Fetch pending appointments
      const appointmentsResponse = await fetch('http://localhost:5002/api/admin/pending-appointments', { headers });
      const appointmentsData = await appointmentsResponse.json();
      setPendingAppointments(appointmentsData);

      // Fetch pending doctors
      const doctorsResponse = await fetch('http://localhost:5002/api/admin/pending-doctors', { headers });
      const doctorsData = await doctorsResponse.json();
      setPendingDoctors(doctorsData);

      // Fetch pending patients
      const patientsResponse = await fetch('http://localhost:5002/api/admin/pending-patients', { headers });
      const patientsData = await patientsResponse.json();
      setPendingPatients(patientsData);

    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApproval = async (type, id, approved) => {
    try {
      const token = localStorage.getItem('adminToken');
      const endpoint = type === 'appointment' 
        ? `http://localhost:5002/api/admin/appointment/${id}/status`
        : `http://localhost:5002/api/admin/${type}/${id}/approval`;

      const body = type === 'appointment' 
        ? { status: approved ? 'approved' : 'rejected' }
        : { approved };

      const response = await fetch(endpoint, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
      });

      if (response.ok) {
        // Refresh data
        fetchData();
      }
    } catch (error) {
      console.error('Error updating approval:', error);
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading dashboard...</p>
      </div>
    );
  }

  return (
    <div className="admin-dashboard">
      <header className="dashboard-header">
        <div className="header-content">
          <h1>Admin Dashboard</h1>
          <div className="admin-info">
            <span>Welcome, {admin?.name || admin?.email}</span>
            <button onClick={onLogout} className="logout-button">
              Logout
            </button>
          </div>
        </div>
      </header>

      <nav className="dashboard-nav">
        <div className="nav-content">
          <button 
            className={`nav-button ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => setActiveTab('overview')}
          >
            Overview
          </button>
          <button 
            className={`nav-button ${activeTab === 'appointments' ? 'active' : ''}`}
            onClick={() => setActiveTab('appointments')}
          >
            Appointments ({pendingAppointments.length})
          </button>
          <button 
            className={`nav-button ${activeTab === 'doctors' ? 'active' : ''}`}
            onClick={() => setActiveTab('doctors')}
          >
            Doctor Approvals ({pendingDoctors.length})
          </button>
          <button 
            className={`nav-button ${activeTab === 'patients' ? 'active' : ''}`}
            onClick={() => setActiveTab('patients')}
          >
            Patient Approvals ({pendingPatients.length})
          </button>
        </div>
      </nav>

      <main className="dashboard-main">
        {activeTab === 'overview' && (
          <>
            <div className="dashboard-grid">
              <div className="dashboard-card">
                <h3>Total Patients</h3>
                <p className="card-number">{stats.patientCount || 0}</p>
                <p className="card-description">Registered patients</p>
              </div>

              <div className="dashboard-card">
                <h3>Total Doctors</h3>
                <p className="card-number">{stats.doctorCount || 0}</p>
                <p className="card-description">Registered doctors</p>
              </div>

              <div className="dashboard-card">
                <h3>Pending Appointments</h3>
                <p className="card-number">{stats.pendingAppointments || 0}</p>
                <p className="card-description">Awaiting approval</p>
              </div>

              <div className="dashboard-card">
                <h3>Pending Approvals</h3>
                <p className="card-number">{(stats.pendingDoctorApprovals || 0) + (stats.pendingPatientApprovals || 0)}</p>
                <p className="card-description">Doctor & Patient approvals</p>
              </div>
            </div>

            <div className="dashboard-section">
              <h2>Recent Activities</h2>
              <div className="activities-list">
                {recentActivities.length > 0 ? (
                  recentActivities.map((activity, index) => (
                    <div key={index} className="activity-item">
                      <div className="activity-content">
                        <p className="activity-message">{activity.message}</p>
                        <p className="activity-time">{formatDate(activity.timestamp)}</p>
                      </div>
                      <span className={`activity-status ${activity.status}`}>
                        {activity.status}
                      </span>
                    </div>
                  ))
                ) : (
                  <p className="no-data">No recent activities</p>
                )}
              </div>
            </div>
          </>
        )}

        {activeTab === 'appointments' && (
          <div className="dashboard-section">
            <h2>Pending Appointment Approvals</h2>
            <div className="approval-list">
              {pendingAppointments.length > 0 ? (
                pendingAppointments.map((appointment) => (
                  <div key={appointment._id} className="approval-item">
                    <div className="approval-content">
                      <h4>Appointment Request</h4>
                      <p><strong>Date:</strong> {formatDate(appointment.appointmentDate)}</p>
                      <p><strong>Time:</strong> {appointment.appointmentTime || 'N/A'}</p>
                      <p><strong>Patient:</strong> {appointment.patientName || 'N/A'}</p>
                      <p><strong>Doctor:</strong> {appointment.doctorName || 'N/A'}</p>
                      <p><strong>Reason:</strong> {appointment.reason || 'N/A'}</p>
                      <p><strong>Requested:</strong> {formatDate(appointment.createdAt)}</p>
                    </div>
                    <div className="approval-actions">
                      <button 
                        className="approve-button"
                        onClick={() => handleApproval('appointment', appointment._id, true)}
                      >
                        Approve
                      </button>
                      <button 
                        className="reject-button"
                        onClick={() => handleApproval('appointment', appointment._id, false)}
                      >
                        Reject
                      </button>
                    </div>
                  </div>
                ))
              ) : (
                <p className="no-data">No pending appointments</p>
              )}
            </div>
          </div>
        )}

        {activeTab === 'doctors' && (
          <div className="dashboard-section">
            <h2>Pending Doctor Approvals</h2>
            <div className="approval-list">
              {pendingDoctors.length > 0 ? (
                pendingDoctors.map((doctor) => (
                  <div key={doctor._id} className="approval-item">
                    <div className="approval-content">
                      <h4>Dr. {doctor.firstName} {doctor.lastName}</h4>
                      <p><strong>Email:</strong> {doctor.email}</p>
                      <p><strong>Phone:</strong> {doctor.phoneNumber}</p>
                      <p><strong>Specialization:</strong> {doctor.specialization || 'N/A'}</p>
                      <p><strong>Experience:</strong> {doctor.experience || 'N/A'} years</p>
                      <p><strong>License:</strong> {doctor.licenseNumber || 'N/A'}</p>
                      <p><strong>Registered:</strong> {formatDate(doctor.createdAt)}</p>
                    </div>
                    <div className="approval-actions">
                      <button 
                        className="approve-button"
                        onClick={() => handleApproval('doctor', doctor._id, true)}
                      >
                        Approve
                      </button>
                      <button 
                        className="reject-button"
                        onClick={() => handleApproval('doctor', doctor._id, false)}
                      >
                        Reject
                      </button>
                    </div>
                  </div>
                ))
              ) : (
                <p className="no-data">No pending doctor approvals</p>
              )}
            </div>
          </div>
        )}

        {activeTab === 'patients' && (
          <div className="dashboard-section">
            <h2>Pending Patient Approvals</h2>
            <div className="approval-list">
              {pendingPatients.length > 0 ? (
                pendingPatients.map((patient) => (
                  <div key={patient._id} className="approval-item">
                    <div className="approval-content">
                      <h4>{patient.firstName} {patient.lastName}</h4>
                      <p><strong>Email:</strong> {patient.email}</p>
                      <p><strong>Phone:</strong> {patient.phoneNumber}</p>
                      <p><strong>Age:</strong> {patient.age || 'N/A'}</p>
                      <p><strong>Gender:</strong> {patient.gender || 'N/A'}</p>
                      <p><strong>Address:</strong> {patient.address || 'N/A'}</p>
                      <p><strong>Registered:</strong> {formatDate(patient.createdAt)}</p>
                    </div>
                    <div className="approval-actions">
                      <button 
                        className="approve-button"
                        onClick={() => handleApproval('patient', patient._id, true)}
                      >
                        Approve
                      </button>
                      <button 
                        className="reject-button"
                        onClick={() => handleApproval('patient', patient._id, false)}
                      >
                        Reject
                      </button>
                    </div>
                  </div>
                ))
              ) : (
                <p className="no-data">No pending patient approvals</p>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;
